package tx_test

import (
	"encoding/hex"
	"fmt"
	"testing"

	cantontx "github.com/cordialsys/crosschain/chain/canton/tx"
	"github.com/stretchr/testify/require"
)

func TestComputeTopologyMultiHashFailures(t *testing.T) {
	t.Parallel()

	_, err := cantontx.ComputeTopologyMultiHash(nil)
	require.ErrorContains(t, err, "topology transactions are empty")

	_, err = cantontx.ComputeTopologyMultiHash([][]byte{{}})
	require.ErrorContains(t, err, "topology transaction is empty")
}

func TestComputeTopologyMultiHash_LiveVector(t *testing.T) {
	t.Parallel()

	type testcase struct {
		transactions []string
		expectedHash string
	}
	var vectors = []testcase{
		{
			transactions: []string{
				"",
			},
			expectedHash: "12206947cbe26cda1680526f5a6957927b9272bc5ca3d2af6dc7946d9c3182bfe8de",
		},
		{
			transactions: []string{
				"",
				"",
			},
			expectedHash: "1220be0f167448e37dc76a3bc98ed58fd8a901bc0c9f2c3fe4336e334d45674a138d",
		},
	}
	for i, vector := range vectors {
		t.Run(fmt.Sprintf("case_%d", i), func(t *testing.T) {
			t.Parallel()

			transactions := make([][]byte, 0, len(vector.transactions))
			for _, transaction := range vector.transactions {
				transaction, err := hex.DecodeString(transaction)
				require.NoError(t, err)
				transactions = append(transactions, transaction)
			}

			hash, err := cantontx.ComputeTopologyMultiHash(transactions)
			require.NoError(t, err)
			require.Equal(t, vector.expectedHash, hex.EncodeToString(hash))
		})
	}

}
